package server

import (
	"context"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	_ "net/http/pprof"
	"time"

	"github.com/tilt-dev/tilt/pkg/apis/core/v1alpha1"

	"github.com/google/uuid"
	"github.com/gorilla/mux"
	_ "github.com/gorilla/websocket"
	jsoniter "github.com/json-iterator/go"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	ctrlclient "sigs.k8s.io/controller-runtime/pkg/client"

	tiltanalytics "github.com/tilt-dev/tilt/internal/analytics"
	"github.com/tilt-dev/tilt/internal/hud/webview"
	"github.com/tilt-dev/tilt/internal/store"
	"github.com/tilt-dev/tilt/internal/store/tiltfiles"
	"github.com/tilt-dev/tilt/pkg/assets"
	"github.com/tilt-dev/tilt/pkg/model"
	proto_webview "github.com/tilt-dev/tilt/pkg/webview"
	"github.com/tilt-dev/wmclient/pkg/analytics"
)

const TiltTokenCookieName = "Tilt-Token"

// CSRF token to protect the websocket. See:
// https://dev.solita.fi/2018/11/07/securing-websocket-endpoints.html
// https://christian-schneider.net/CrossSiteWebSocketHijacking.html
var websocketCSRFToken = uuid.New()

type analyticsPayload struct {
	Verb string            `json:"verb"`
	Name string            `json:"name"`
	Tags map[string]string `json:"tags"`
}

type analyticsOptPayload struct {
	Opt string `json:"opt"`
}

type triggerPayload struct {
	ManifestNames []string          `json:"manifest_names"`
	BuildReason   model.BuildReason `json:"build_reason"`
}

type overrideTriggerModePayload struct {
	ManifestNames []string `json:"manifest_names"`
	TriggerMode   int      `json:"trigger_mode"`
}

type HeadsUpServer struct {
	ctx        context.Context
	store      *store.Store
	router     *mux.Router
	a          *tiltanalytics.TiltAnalytics
	wsList     *WebsocketList
	ctrlClient ctrlclient.Client
}

func ProvideHeadsUpServer(
	ctx context.Context,
	store *store.Store,
	assetServer assets.Server,
	analytics *tiltanalytics.TiltAnalytics,
	wsList *WebsocketList,
	ctrlClient ctrlclient.Client) (*HeadsUpServer, error) {
	r := mux.NewRouter().UseEncodedPath()
	s := &HeadsUpServer{
		ctx:        ctx,
		store:      store,
		router:     r,
		a:          analytics,
		wsList:     wsList,
		ctrlClient: ctrlClient,
	}

	r.HandleFunc("/api/view", s.ViewJSON)
	r.HandleFunc("/api/dump/engine", s.DumpEngineJSON)
	r.HandleFunc("/api/analytics", s.HandleAnalytics)
	r.HandleFunc("/api/analytics_opt", s.HandleAnalyticsOpt)
	r.HandleFunc("/api/trigger", s.HandleTrigger)
	r.HandleFunc("/api/override/trigger_mode", s.HandleOverrideTriggerMode)
	// this endpoint is only used for testing snapshots in development
	r.HandleFunc("/api/snapshot/{snapshot_id}", s.SnapshotJSON)
	r.HandleFunc("/api/websocket_token", s.WebsocketToken)
	r.HandleFunc("/ws/view", s.ViewWebsocket)
	r.HandleFunc("/api/set_tiltfile_args", s.HandleSetTiltfileArgs).Methods("POST")

	r.PathPrefix("/").Handler(s.cookieWrapper(assetServer))

	return s, nil
}

type funcHandler struct {
	f func(w http.ResponseWriter, r *http.Request)
}

func (fh funcHandler) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	fh.f(w, r)
}

func (s *HeadsUpServer) cookieWrapper(handler http.Handler) http.Handler {
	return funcHandler{f: func(w http.ResponseWriter, r *http.Request) {
		state := s.store.RLockState()
		http.SetCookie(w, &http.Cookie{Name: TiltTokenCookieName, Value: string(state.Token), Path: "/"})
		s.store.RUnlockState()
		handler.ServeHTTP(w, r)
	}}
}

func (s *HeadsUpServer) Router() http.Handler {
	return s.router
}

func (s *HeadsUpServer) ViewJSON(w http.ResponseWriter, req *http.Request) {
	view, err := webview.CompleteView(req.Context(), s.ctrlClient, s.store)
	if err != nil {
		http.Error(w, fmt.Sprintf("Error converting view to proto: %v", err), http.StatusInternalServerError)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	err = json.NewEncoder(w).Encode(view)
	if err != nil {
		http.Error(w, fmt.Sprintf("Error rendering view payload: %v", err), http.StatusInternalServerError)
	}
}

// Dump the JSON engine over http. Only intended for 'tilt dump engine'.
func (s *HeadsUpServer) DumpEngineJSON(w http.ResponseWriter, req *http.Request) {
	state := s.store.RLockState()
	defer s.store.RUnlockState()

	encoder := store.CreateEngineStateEncoder(w)
	err := encoder.Encode(state)
	if err != nil {
		log.Printf("Error encoding: %v", err)
	}
}

func (s *HeadsUpServer) SnapshotJSON(w http.ResponseWriter, req *http.Request) {
	view, err := webview.CompleteView(req.Context(), s.ctrlClient, s.store)
	if err != nil {
		http.Error(w, fmt.Sprintf("Error converting view to proto: %v", err), http.StatusInternalServerError)
		return
	}

	snapshot := &proto_webview.Snapshot{
		View:      view,
		CreatedAt: metav1.NewMicroTime(time.Now()),
	}

	w.Header().Set("Content-Type", "application/json")
	err = json.NewEncoder(w).Encode(snapshot)
	if err != nil {
		http.Error(w, fmt.Sprintf("Error rendering view payload: %v", err), http.StatusInternalServerError)
	}
}

func (s *HeadsUpServer) HandleAnalyticsOpt(w http.ResponseWriter, req *http.Request) {
	if req.Method != http.MethodPost {
		http.Error(w, "must be POST request", http.StatusBadRequest)
		return
	}

	var payload analyticsOptPayload

	decoder := json.NewDecoder(req.Body)
	err := decoder.Decode(&payload)
	if err != nil {
		http.Error(w, fmt.Sprintf("error parsing JSON payload: %v", err), http.StatusBadRequest)
		return
	}

	opt, err := analytics.ParseOpt(payload.Opt)
	if err != nil {
		http.Error(w, fmt.Sprintf("error parsing opt '%s': %v", payload.Opt, err), http.StatusBadRequest)
	}

	// only logging on opt-in, because, well, opting out means the user just told us not to report data on them!
	if opt == analytics.OptIn {
		s.a.Incr("analytics.opt.in", nil)
	}

	s.store.Dispatch(store.AnalyticsUserOptAction{Opt: opt})
}

func (s *HeadsUpServer) HandleAnalytics(w http.ResponseWriter, req *http.Request) {
	if req.Method != http.MethodPost {
		http.Error(w, "must be POST request", http.StatusBadRequest)
		return
	}

	var payloads []analyticsPayload

	decoder := json.NewDecoder(req.Body)
	err := decoder.Decode(&payloads)
	if err != nil {
		http.Error(w, fmt.Sprintf("error parsing JSON payload: %v", err), http.StatusBadRequest)
		return
	}

	for _, p := range payloads {
		if p.Verb != "incr" {
			http.Error(w, "error parsing payloads: only incr verbs are supported", http.StatusBadRequest)
			return
		}

		s.a.Incr(p.Name, p.Tags)
	}
}

func (s *HeadsUpServer) HandleSetTiltfileArgs(w http.ResponseWriter, req *http.Request) {
	var args []string
	err := jsoniter.NewDecoder(req.Body).Decode(&args)
	if err != nil {
		http.Error(w, fmt.Sprintf("error parsing JSON payload: %v", err), http.StatusBadRequest)
		return
	}

	ctx := req.Context()
	err = tiltfiles.SetTiltfileArgs(ctx, s.ctrlClient, args)
	if err != nil {
		http.Error(w, fmt.Sprintf("error updating apiserver: %v", err), http.StatusInternalServerError)
		return
	}
}

// Responds with:
// * 200/empty body on success
// * 200/error message in body on well-formed, unservicable requests (e.g. resource is disabled or doesn't exist)
// * 400/error message in body on badly formed requests (e.g., invalid json)
func (s *HeadsUpServer) HandleTrigger(w http.ResponseWriter, req *http.Request) {
	if req.Method != http.MethodPost {
		http.Error(w, "must be POST request", http.StatusBadRequest)
		return
	}

	var payload triggerPayload

	decoder := json.NewDecoder(req.Body)
	err := decoder.Decode(&payload)
	if err != nil {
		http.Error(w, fmt.Sprintf("error parsing JSON payload: %v", err), http.StatusBadRequest)
		return
	}

	if len(payload.ManifestNames) != 1 {
		http.Error(w, fmt.Sprintf("/api/trigger currently supports exactly one manifest name, got %d", len(payload.ManifestNames)), http.StatusBadRequest)
		return
	}

	mn := model.ManifestName(payload.ManifestNames[0])

	state := s.store.RLockState()
	defer s.store.RUnlockState()
	ms, ok := state.ManifestState(mn)
	if !ok {
		http.Error(w, fmt.Sprintf("resource %q does not exist", mn), http.StatusNotFound)
	} else if ms != nil && ms.DisableState == v1alpha1.DisableStateDisabled {
		_, _ = fmt.Fprintf(w, "resource %q is currently disabled", mn)
	} else {
		s.store.Dispatch(store.AppendToTriggerQueueAction{Name: mn, Reason: payload.BuildReason})
	}
}

func (s *HeadsUpServer) HandleOverrideTriggerMode(w http.ResponseWriter, req *http.Request) {
	if req.Method != http.MethodPost {
		http.Error(w, "must be POST request", http.StatusBadRequest)
		return
	}

	var payload overrideTriggerModePayload

	decoder := json.NewDecoder(req.Body)
	decoder.DisallowUnknownFields()
	err := decoder.Decode(&payload)
	if err != nil {
		http.Error(w, fmt.Sprintf("error parsing JSON payload: %v", err), http.StatusBadRequest)
		return
	}

	err = checkManifestsExist(s.store, payload.ManifestNames)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	if !model.ValidTriggerMode(model.TriggerMode(payload.TriggerMode)) {
		http.Error(w, fmt.Sprintf("invalid trigger mode: %d", payload.TriggerMode), http.StatusBadRequest)
		return
	}

	s.store.Dispatch(OverrideTriggerModeAction{
		ManifestNames: model.ManifestNames(payload.ManifestNames),
		TriggerMode:   model.TriggerMode(payload.TriggerMode),
	})
}

func (s *HeadsUpServer) WebsocketToken(w http.ResponseWriter, req *http.Request) {
	w.Header().Set("Content-Type", "text/plain")
	_, _ = w.Write([]byte(websocketCSRFToken.String()))
}

func checkManifestsExist(st store.RStore, mNames []string) error {
	state := st.RLockState()
	defer st.RUnlockState()
	for _, mName := range mNames {
		if _, ok := state.ManifestState(model.ManifestName(mName)); !ok {
			return fmt.Errorf("no manifest found with name '%s'", mName)
		}
	}
	return nil
}

package server

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"sort"
	"sync"
	"time"

	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/types"
	"k8s.io/client-go/util/workqueue"
	ctrlclient "sigs.k8s.io/controller-runtime/pkg/client"

	"github.com/tilt-dev/tilt/internal/hud/server/gorilla"
	"github.com/tilt-dev/tilt/internal/hud/webview"
	"github.com/tilt-dev/tilt/internal/store"
	"github.com/tilt-dev/tilt/pkg/apis/core/v1alpha1"
	"github.com/tilt-dev/tilt/pkg/logger"
	"github.com/tilt-dev/tilt/pkg/model/logstore"
	proto_webview "github.com/tilt-dev/tilt/pkg/webview"

	"github.com/gorilla/websocket"
)

var upgrader = websocket.Upgrader{
	ReadBufferSize:  1024,
	WriteBufferSize: 1024,

	// Disable compression due to safari bugs in websockets, see:
	// https://github.com/tilt-dev/tilt/issues/4746
	//
	// Though, frankly, we probably don't need compression
	// anyway, since it's not like you're using Tilt over
	// a mobile network.
	EnableCompression: false,

	// Allow the connection if either:
	//
	// 1) The client has a CSRF token, or
	// 2) The origin matches what we expect.
	//
	// Once a few releases have gone by we should remove the origin check.
	// (since we know some tilt users expect tabs to stay open
	// across releases).
	CheckOrigin: func(req *http.Request) bool {
		if websocketCSRFToken.String() == req.URL.Query().Get("csrf") {
			return true
		}

		// If the CSRF check fails, fallback to an origin check.
		return gorilla.CheckSameOrigin(req)
	},
}

type WebsocketSubscriber struct {
	ctx        context.Context
	st         store.RStore
	ctrlClient ctrlclient.Client
	mu         sync.Mutex
	conn       WebsocketConn

	q                workqueue.TypedInterface[bool]
	dirtyUIResources map[string]*v1alpha1.UIResource
	dirtyUIButtons   map[string]*v1alpha1.UIButton
	dirtyUISession   *v1alpha1.UISession
	dirtyClusters    map[string]*v1alpha1.Cluster

	tiltStartTime    metav1.MicroTime
	clientCheckpoint logstore.Checkpoint
}

type WebsocketConn interface {
	NextReader() (int, io.Reader, error)
	Close() error
	NextWriter(messageType int) (io.WriteCloser, error)
}

var _ WebsocketConn = &websocket.Conn{}

func NewWebsocketSubscriber(ctx context.Context, ctrlClient ctrlclient.Client, st store.RStore, conn WebsocketConn) *WebsocketSubscriber {
	return &WebsocketSubscriber{
		ctx:              ctx,
		ctrlClient:       ctrlClient,
		st:               st,
		conn:             conn,
		q:                workqueue.NewTyped[bool](),
		dirtyUIButtons:   make(map[string]*v1alpha1.UIButton),
		dirtyUIResources: make(map[string]*v1alpha1.UIResource),
		dirtyClusters:    make(map[string]*v1alpha1.Cluster),
	}
}

func (ws *WebsocketSubscriber) TearDown(ctx context.Context) {
	_ = ws.conn.Close()
}

// Should be called exactly once. Consumes messages until the socket closes.
func (ws *WebsocketSubscriber) Stream(ctx context.Context) {
	ctx, cancel := context.WithCancel(ctx)
	defer cancel()

	go func() {
		// No-op consumption of all control messages, as recommended here:
		// https://godoc.org/github.com/gorilla/websocket#hdr-Control_Messages
		conn := ws.conn
		for {
			_, _, err := conn.NextReader()
			if err != nil {
				ws.q.ShutDown()
				cancel()
				break
			}
		}
	}()

	// initialize the stream with a full view
	view, err := webview.CompleteView(ctx, ws.ctrlClient, ws.st)
	if err != nil {
		// not much to do
		return
	}

	ws.sendView(ctx, view)

	if view.UiSession != nil {
		ws.onSessionUpdateSent(ctx, view.UiSession)
	}

	debouncer := time.NewTimer(200 * time.Millisecond)
	defer func() {
		if !debouncer.Stop() {
			<-debouncer.C
		}
	}()
	for {
		item, shutdown := ws.q.Get()
		if shutdown {
			return
		}

		view := ws.toViewUpdate()
		if view != nil {
			ws.sendView(ctx, view)

			if view.UiSession != nil {
				ws.onSessionUpdateSent(ctx, view.UiSession)
			}
		}

		ws.q.Done(item)

		select {
		case <-debouncer.C:
		case <-ctx.Done():
		}
		debouncer.Reset(200 * time.Millisecond)
	}
}

func (ws *WebsocketSubscriber) OnChange(ctx context.Context, s store.RStore, summary store.ChangeSummary) error {
	// Currently, we only broadcast log changes from this OnChange handler.
	// Everything else should be handled by reconcilers from the apiserver
	if !summary.Log {
		return nil
	}

	ws.q.Add(true)
	return nil
}

// Sends a UISession update on the websocket.
func (ws *WebsocketSubscriber) SendUISessionUpdate(ctx context.Context, uiSession *v1alpha1.UISession) {
	ws.mu.Lock()
	ws.dirtyUISession = uiSession
	ws.mu.Unlock()

	ws.q.Add(true)
}

// If a session update triggered an analytics nudge, record it so that we don't
// nudge again.
func (ws *WebsocketSubscriber) onSessionUpdateSent(ctx context.Context, uiSession *v1alpha1.UISession) {
	state := ws.st.RLockState()
	surfaced := !state.AnalyticsNudgeSurfaced
	ws.st.RUnlockState()

	if uiSession != nil && uiSession.Status.NeedsAnalyticsNudge && !surfaced {
		// If we're showing the nudge and no one's told the engine
		// state about it yet... tell the engine state.
		ws.st.Dispatch(store.AnalyticsNudgeSurfacedAction{})
	}
}

// Sends a UIResource update on the websocket.
func (ws *WebsocketSubscriber) SendUIResourceUpdate(ctx context.Context, nn types.NamespacedName, uiResource *v1alpha1.UIResource) {
	if uiResource == nil {
		// If the UI resource doesn't exist, send a fake one down the
		// stream that the UI will interpret as deletion.
		now := metav1.Now()
		uiResource = &v1alpha1.UIResource{
			ObjectMeta: metav1.ObjectMeta{
				Name:              nn.Name,
				DeletionTimestamp: &now,
			},
		}
	}

	ws.mu.Lock()
	ws.dirtyUIResources[nn.Name] = uiResource
	ws.mu.Unlock()
	ws.q.Add(true)
}

// Sends a UIButton update on the websocket.
func (ws *WebsocketSubscriber) SendUIButtonUpdate(ctx context.Context, nn types.NamespacedName, uiButton *v1alpha1.UIButton) {
	if uiButton == nil {
		// If the UI button doesn't exist, send a fake one down the
		// stream that the UI will interpret as deletion.
		now := metav1.Now()
		uiButton = &v1alpha1.UIButton{
			ObjectMeta: metav1.ObjectMeta{
				Name:              nn.Name,
				DeletionTimestamp: &now,
			},
		}
	}

	ws.mu.Lock()
	ws.dirtyUIButtons[nn.Name] = uiButton
	ws.mu.Unlock()
	ws.q.Add(true)
}

func (ws *WebsocketSubscriber) SendClusterUpdate(
	_ context.Context,
	nn types.NamespacedName,
	cluster *v1alpha1.Cluster,
) {
	if cluster == nil {
		// If the cluster doesn't exist, send a fake one down the
		// stream that the UI will interpret as deletion.
		now := metav1.Now()
		cluster = &v1alpha1.Cluster{
			ObjectMeta: metav1.ObjectMeta{
				Name:              nn.Name,
				DeletionTimestamp: &now,
			},
		}
	}

	ws.mu.Lock()
	ws.dirtyClusters[nn.Name] = cluster
	ws.mu.Unlock()
	ws.q.Add(true)
}

// Sends all the objects that have changed since the last send.
func (ws *WebsocketSubscriber) toViewUpdate() *proto_webview.View {
	view, err := webview.LogUpdate(ws.st, ws.clientCheckpoint)
	if err != nil {
		return nil // Not much we can do on error right now.
	}

	ws.mu.Lock()
	defer ws.mu.Unlock()

	// [-1,-1) means there are no logs
	if view.LogList.ToCheckpoint == -1 && view.LogList.FromCheckpoint == -1 {
		view.LogList = nil
	}
	hasChanges := view.LogList != nil

	if ws.dirtyUISession != nil {
		view.UiSession = ws.dirtyUISession
		ws.dirtyUISession = nil
		hasChanges = true
	}

	for k, obj := range ws.dirtyUIResources {
		view.UiResources = append(view.UiResources, *obj)
		delete(ws.dirtyUIResources, k)
		hasChanges = true
	}
	sort.Slice(view.UiResources, func(i, j int) bool {
		return view.UiResources[i].Name < view.UiResources[j].Name
	})

	for k, obj := range ws.dirtyUIButtons {
		view.UiButtons = append(view.UiButtons, *obj)
		delete(ws.dirtyUIButtons, k)
		hasChanges = true
	}
	sort.Slice(view.UiButtons, func(i, j int) bool {
		return view.UiButtons[i].Name < view.UiButtons[j].Name
	})

	for k, obj := range ws.dirtyClusters {
		view.Clusters = append(view.Clusters, *obj)
		delete(ws.dirtyClusters, k)
		hasChanges = true
	}
	sort.Slice(view.Clusters, func(i, j int) bool {
		return view.Clusters[i].Name < view.Clusters[j].Name
	})

	if !hasChanges {
		return nil
	}
	return view
}

// Sends the view to the websocket.
func (ws *WebsocketSubscriber) sendView(ctx context.Context, view *proto_webview.View) {
	if view.LogList != nil && view.LogList.ToCheckpoint != -1 {
		ws.clientCheckpoint = logstore.Checkpoint(view.LogList.ToCheckpoint)
	}

	// A little hack that initializes tiltStartTime for this websocket
	// on the first send.
	if ws.tiltStartTime.IsZero() {
		ws.tiltStartTime = view.TiltStartTime
	}

	w, err := ws.conn.NextWriter(websocket.TextMessage)
	if err != nil {
		logger.Get(ctx).Verbosef("getting writer: %v", err)
		return
	}
	defer func() {
		err := w.Close()
		if err != nil {
			logger.Get(ctx).Verbosef("error closing websocket writer: %v", err)
		}
	}()

	err = json.NewEncoder(w).Encode(view)
	if err != nil {
		logger.Get(ctx).Verbosef("sending webview data: %v", err)
	}
}

func (s *HeadsUpServer) ViewWebsocket(w http.ResponseWriter, req *http.Request) {
	conn, err := upgrader.Upgrade(w, req, nil)
	if err != nil {
		http.Error(w, fmt.Sprintf("Error upgrading websocket: %v", err), http.StatusInternalServerError)
		return
	}

	ws := NewWebsocketSubscriber(s.ctx, s.ctrlClient, s.store, conn)
	s.wsList.Add(ws)
	_ = s.store.AddSubscriber(s.ctx, ws)

	ws.Stream(s.ctx)

	// When we remove ourselves as a subscriber, the Store waits for any outstanding OnChange
	// events to complete, then calls TearDown.
	_ = s.store.RemoveSubscriber(context.Background(), ws)
	s.wsList.Remove(ws)
}

var _ store.TearDowner = &WebsocketSubscriber{}

package server

import (
	"context"
	"crypto/tls"
	"fmt"
	"io"
	"log"
	"net/http"
	"regexp"

	"github.com/gorilla/mux"
	genericapiserver "k8s.io/apiserver/pkg/server"
	"k8s.io/client-go/rest"
	"k8s.io/client-go/tools/clientcmd"
	clientcmdapi "k8s.io/client-go/tools/clientcmd/api"
	"k8s.io/kubectl/pkg/proxy"

	"github.com/tilt-dev/tilt-apiserver/pkg/server/start"
	"github.com/tilt-dev/tilt/internal/filelock"
	"github.com/tilt-dev/tilt/internal/store"
	"github.com/tilt-dev/tilt/pkg/assets"
	"github.com/tilt-dev/tilt/pkg/model"
)

// apiServerProxyPrefix routes web HUD requests to the apiserver as it cannot contact it directly.
//
// This prefix is stripped from the subsequent request to the apiserver, e.g. to list API versions,
// `/proxy/apis` --> `/apis`.
//
// NOTE: The kubectl ProxyHandler code has some odd behavior in this regard in that it only strips
//
//	the prefix if it does not start with `/api`. As a result, something like a prefix of `/apiserver`
//	will cause problems because `/apiserver/apis/foo` will be passed as-is, which is why `/proxy` was
//	chosen here.
const apiServerProxyPrefix = "/proxy"

type HeadsUpServerController struct {
	// configAccess may be nil in cases where we don't
	// want to persist the config to disk.
	configAccess clientcmd.ConfigAccess

	apiServerName   model.APIServerName
	webListener     WebListener
	hudServer       *HeadsUpServer
	assetServer     assets.Server
	apiServer       *http.Server
	webServer       *http.Server
	webURL          model.WebURL
	apiServerConfig *APIServerConfig

	shutdown func()
}

func ProvideHeadsUpServerController(
	configAccess clientcmd.ConfigAccess,
	apiServerName model.APIServerName,
	webListener WebListener,
	apiServerConfig *APIServerConfig,
	hudServer *HeadsUpServer,
	assetServer assets.Server,
	webURL model.WebURL) *HeadsUpServerController {

	emptyCh := make(chan struct{})
	close(emptyCh)

	return &HeadsUpServerController{
		configAccess:    configAccess,
		apiServerName:   apiServerName,
		webListener:     webListener,
		hudServer:       hudServer,
		assetServer:     assetServer,
		webURL:          webURL,
		apiServerConfig: apiServerConfig,
		shutdown:        func() {},
	}
}

func (s *HeadsUpServerController) TearDown(ctx context.Context) {
	s.shutdown()
	s.assetServer.TearDown(ctx)

	// Close all active connections immediately.
	// Tilt is deleting all its state, so there's no good
	// reason to handle graceful shutdown.
	_ = s.webServer.Close()
	_ = s.apiServer.Close()

	_ = s.removeFromAPIServerConfig()
}

func (s *HeadsUpServerController) OnChange(ctx context.Context, st store.RStore, _ store.ChangeSummary) error {
	return nil
}

// Merge the APIServer and the Tilt Web server into a single handler,
// and attach them both to the public listener.
func (s *HeadsUpServerController) SetUp(ctx context.Context, st store.RStore) error {
	ctx, cancel := context.WithCancel(ctx)
	s.shutdown = cancel

	err := s.setUpHelper(ctx, st)
	if err != nil {
		return fmt.Errorf("Cannot start the tilt-apiserver: %v", err)
	}
	err = s.addToAPIServerConfig()
	if err != nil {
		return fmt.Errorf("writing tilt api configs: %v", err)
	}
	return nil
}

func (s *HeadsUpServerController) setUpHelper(ctx context.Context, st store.RStore) error {
	config := s.apiServerConfig
	server, err := config.Complete().New()
	if err != nil {
		return err
	}

	err = server.GenericAPIServer.AddPostStartHook("start-tilt-server-informers", func(context genericapiserver.PostStartHookContext) error {
		if config.GenericConfig.SharedInformerFactory != nil {
			config.GenericConfig.SharedInformerFactory.Start(context.Context.Done())
		}
		return nil
	})
	if err != nil {
		return err
	}

	prepared := server.GenericAPIServer.PrepareRun()
	apiserverHandler := prepared.Handler
	serving := config.ExtraConfig.ServingInfo

	apiRouter := mux.NewRouter()
	apiRouter.Path("/api").Handler(http.NotFoundHandler())
	apiRouter.PathPrefix("/apis").Handler(apiserverHandler)
	apiRouter.PathPrefix("/healthz").Handler(apiserverHandler)
	apiRouter.PathPrefix("/livez").Handler(apiserverHandler)
	apiRouter.PathPrefix("/metrics").Handler(apiserverHandler)
	apiRouter.PathPrefix("/openapi").Handler(apiserverHandler)
	apiRouter.PathPrefix("/readyz").Handler(apiserverHandler)
	apiRouter.PathPrefix("/swagger").Handler(apiserverHandler)
	apiRouter.PathPrefix("/version").Handler(apiserverHandler)
	apiRouter.PathPrefix("/debug").Handler(http.DefaultServeMux) // for /debug/pprof

	var apiTLSConfig *tls.Config
	if serving.Cert != nil {
		apiTLSConfig, err = start.TLSConfig(ctx, serving)
		if err != nil {
			return fmt.Errorf("Starting apiserver: %v", err)
		}
	}

	proxyHandler, err := newAPIServerProxyHandler(config.GenericConfig.LoopbackClientConfig)
	if err != nil {
		return fmt.Errorf("failed to create apiserver proxy: %v", err)
	}

	webRouter := mux.NewRouter()
	webRouter.PathPrefix("/debug").Handler(http.DefaultServeMux) // for /debug/pprof
	// the path prefix here must be kept in sync with the prefix configured in the proxy handler
	// (it needs to know what to strip before forwarding the request)
	webRouter.PathPrefix(apiServerProxyPrefix).Handler(proxyHandler)
	webRouter.PathPrefix("/").Handler(s.hudServer.Router())

	s.webServer = &http.Server{
		Addr:    s.webListener.Addr().String(),
		Handler: webRouter,

		// blackhole any server errors
		ErrorLog: log.New(io.Discard, "", 0),
	}
	runServer(ctx, s.webServer, s.webListener)

	s.apiServer = &http.Server{
		Addr:           serving.Listener.Addr().String(),
		Handler:        apiRouter,
		MaxHeaderBytes: 1 << 20,
		TLSConfig:      apiTLSConfig,

		// blackhole any server errors
		ErrorLog: log.New(io.Discard, "", 0),
	}
	runServer(ctx, s.apiServer, serving.Listener)
	server.GenericAPIServer.RunPostStartHooks(ctx)

	go func() {
		err := s.assetServer.Serve(ctx)
		if err != nil && ctx.Err() == nil {
			st.Dispatch(store.NewErrorAction(err))
		}
	}()

	return nil
}

// Write the API server configs into the user settings directory.
//
// Usually shows up as ~/.windmill/config or ~/.tilt-dev/config.
func (s *HeadsUpServerController) addToAPIServerConfig() error {
	if s.configAccess == nil {
		return nil
	}

	var newConfig *clientcmdapi.Config
	err := filelock.WithRLock(s.configAccess, func() error {
		var e error
		newConfig, e = s.configAccess.GetStartingConfig()
		return e
	})
	if err != nil {
		return err
	}
	newConfig = newConfig.DeepCopy()

	clientConfig := s.apiServerConfig.GenericConfig.LoopbackClientConfig
	if err := model.ValidateAPIServerName(s.apiServerName); err != nil {
		return err
	}

	name := string(s.apiServerName)
	newConfig.Contexts[name] = &clientcmdapi.Context{
		Cluster:  name,
		AuthInfo: name,
	}
	newConfig.AuthInfos[name] = &clientcmdapi.AuthInfo{
		Token: clientConfig.BearerToken,
	}

	newConfig.Clusters[name] = &clientcmdapi.Cluster{
		Server:                   clientConfig.Host,
		CertificateAuthorityData: clientConfig.TLSClientConfig.CAData,
	}

	return s.modifyConfig(*newConfig)
}

// Remove this API server's configs into the user settings directory.
//
// Usually shows up as ~/.windmill/config or ~/.tilt-dev/config.
func (s *HeadsUpServerController) removeFromAPIServerConfig() error {
	if s.configAccess == nil {
		return nil
	}

	var newConfig *clientcmdapi.Config
	err := filelock.WithRLock(s.configAccess, func() error {
		var e error
		newConfig, e = s.configAccess.GetStartingConfig()
		return e
	})
	if err != nil {
		return err
	}
	newConfig = newConfig.DeepCopy()
	if err := model.ValidateAPIServerName(s.apiServerName); err != nil {
		return err
	}

	name := string(s.apiServerName)
	delete(newConfig.Contexts, name)
	delete(newConfig.AuthInfos, name)
	delete(newConfig.Clusters, name)

	return s.modifyConfig(*newConfig)
}

func (s *HeadsUpServerController) modifyConfig(config clientcmdapi.Config) error {
	return filelock.WithLock(s.configAccess, func() error {
		return clientcmd.ModifyConfig(s.configAccess, config, true)
	})
}

func newAPIServerProxyHandler(config *rest.Config) (http.Handler, error) {
	// all requests to the proxy handler are same origin from the HUD server, so there is
	// no CORS policy in place because we explicitly want to reject all other origin requests
	// in the future, it's worth considering adding a CSRF token for a bit of extra robustness;
	// but it's not critical because the content returned by the proxy for GETs is not embeddable
	// and for POST cannot accept form data (only JSON or protobuf), so XHR same origin policy
	// is sufficient
	fs := &proxy.FilterServer{
		AcceptHosts: []*regexp.Regexp{
			// filtering by Host header is not useful, just ignore it
			regexp.MustCompile(`.+`),
		},
		AcceptPaths: []*regexp.Regexp{
			regexp.MustCompile(`^/apis/tilt\.dev/\w+/uibuttons`),
		},
	}

	// the prefix here must be kept in sync with the route definition on the mux
	return proxy.NewProxyHandler(apiServerProxyPrefix, fs, config, 0, false)
}

var _ store.SetUpper = &HeadsUpServerController{}
var _ store.TearDowner = &HeadsUpServerController{}

